  1→import React, { useCallback, useEffect, useRef, useState } from 'react';
  2→import { addons } from 'storybook/internal/manager-api';
  3→import { useStorybookState } from 'storybook/internal/manager-api';
  4→import { useTheme } from 'storybook/internal/theming';
  5→import { EVENTS } from './constants';
  6→import { useIndexedDB } from './useIndexedDB';
  7→import { CodeMirrorEditor, type CodeMirrorEditorHandle } from './CodeMirrorEditor';
  8→import JSON5 from 'json5';
  9→
 10→function idbKeyFor(storyId: string) {
 11→  return `sdui-json-${storyId}`;
 12→}
 13→
 14→function getChannel() {
 15→  try { return addons.getChannel(); } catch { return null; }
 16→}
 17→
 18→function tryParse(text: string): { parsed: any; error: string | null } {
 19→  try {
 20→    return { parsed: JSON.parse(text), error: null };
 21→  } catch {
 22→    try {
 23→      return { parsed: JSON5.parse(text), error: null };
 24→    } catch (e) {
 25→      return { parsed: null, error: (e as Error).message };
 26→    }
 27→  }
 28→}
 29→
 30→export function JsonEditorPanel() {
 31→  const state = useStorybookState();
 32→  const storyId = state.storyId ?? '';
 33→  const theme = useTheme();
 34→  const isDarkMode = theme.base === 'dark';
 35→
 36→  const [defaultJson, setDefaultJson] = useState<string>('');
 37→  const [text, setText] = useState<string>('');
 38→  const [error, setError] = useState<string | null>(null);
 39→  const [dirty, setDirty] = useState(false);
 40→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 41→  const editorRef = useRef<CodeMirrorEditorHandle>(null);
 42→  const retryRef = useRef<ReturnType<typeof setInterval> | null>(null);
 43→  const prevStoryIdRef = useRef<string>('');
 44→
 45→  const { stored, save, remove, ready } = useIndexedDB(idbKeyFor(storyId));
 46→
 47→  useEffect(() => {
 48→    return () => {
 49→      if (debounceRef.current) clearTimeout(debounceRef.current);
 50→      if (retryRef.current) clearInterval(retryRef.current);
 51→    };
 52→  }, []);
 53→
 54→  useEffect(() => {
 55→    if (prevStoryIdRef.current && prevStoryIdRef.current !== storyId) {
 56→      setDefaultJson('');
 57→      setText('');
 58→      setError(null);
 59→      setDirty(false);
 60→    }
 61→    prevStoryIdRef.current = storyId;
 62→  }, [storyId]);
 63→
 64→  useEffect(() => {
 65→    const channel = getChannel();
 66→    if (!channel) return;
 67→
 68→    const onSetDefault = (json: string) => {
 69→      setDefaultJson(json);
 70→      if (retryRef.current) {
 71→        clearInterval(retryRef.current);
 72→        retryRef.current = null;
 73→      }
 74→    };
 75→
 76→    channel.on(EVENTS.SET_DEFAULT_JSON, onSetDefault);
 77→    channel.emit(EVENTS.REQUEST_DEFAULT);
 78→
 79→    let retryCount = 0;
 80→    retryRef.current = setInterval(() => {
 81→      retryCount++;
 82→      if (retryCount > 20) {
 83→        if (retryRef.current) clearInterval(retryRef.current);
 84→        return;
 85→      }
 86→      channel.emit(EVENTS.REQUEST_DEFAULT);
 87→    }, 250);
 88→
 89→    return () => {
 90→      channel.off(EVENTS.SET_DEFAULT_JSON, onSetDefault);
 91→      if (retryRef.current) {
 92→        clearInterval(retryRef.current);
 93→        retryRef.current = null;
 94→      }
 95→    };
 96→  }, [storyId]);
 97→
 98→  useEffect(() => {
 99→    if (!ready || !defaultJson) return;
100→    const initial = stored ?? defaultJson;
101→    setText(initial);
102→    editorRef.current?.setValue(initial);
103→    setDirty(!!stored);
104→    setError(null);
105→  }, [ready, stored, defaultJson, storyId]);
106→
107→  const handleChange = useCallback(
108→    (value: string) => {
109→      setText(value);
110→
111→      if (debounceRef.current) clearTimeout(debounceRef.current);
112→
113→      debounceRef.current = setTimeout(() => {
114→        const { parsed, error: parseErr } = tryParse(value);
115→        if (parsed !== null) {
116→          save(value);
117→          setDirty(true);
118→          getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
119→        } else {
120→          save(value);
121→          setDirty(true);
122→        }
123→      }, 400);
124→    },
125→    [save],
126→  );
127→
128→  const handleValidationChange = useCallback(
129→    (hasErrors: boolean, message: string | null) => {
130→      setError(hasErrors ? message : null);
131→    },
132→    [],
133→  );
134→
135→  const handleReset = useCallback(() => {
136→    remove();
137→    setText(defaultJson);
138→    editorRef.current?.setValue(defaultJson);
139→    setDirty(false);
140→    setError(null);
141→    const { parsed } = tryParse(defaultJson);
142→    if (parsed !== null) {
143→      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
144→    }
145→  }, [defaultJson, remove]);
146→
147→  const handleFormat = useCallback(() => {
148→    const currentText = editorRef.current?.getValue() ?? '';
149→    const { parsed, error: parseErr } = tryParse(currentText);
150→    if (parsed !== null) {
151→      const formatted = JSON.stringify(parsed, null, 2);
152→      setText(formatted);
153→      editorRef.current?.setValue(formatted);
154→      save(formatted);
155→      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
156→      setError(null);
157→    } else {
158→      setError(parseErr);
159→    }
160→  }, [save]);
161→
162→  const s = isDarkMode ? darkStyles : lightStyles;
163→
164→  if (!storyId) {
165→    return <div style={s.empty}>Select a story to edit its JSON.</div>;
166→  }
167→
168→  const isWaiting = !defaultJson && !text;
169→
170→  return (
171→    <div style={s.container}>
172→      <div style={s.toolbar}>
173→        <span style={s.label}>
174→          SDUI JSON {dirty && <span style={s.badge}>edited</span>}
175→        </span>
176→        <div style={s.actions}>
177→          <button
178→            style={s.btn}
179→            onClick={handleFormat}
180→            title="Format JSON (normalizes to strict JSON)"
181→          >
182→            Format
183→          </button>
184→          <button
185→            style={{ ...s.btn, ...(dirty ? s.btnReset : s.btnDisabled) }}
186→            onClick={handleReset}
187→            disabled={!dirty}
188→            title="Reset to story default"
189→          >
190→            Reset
191→          </button>
192→        </div>
193→      </div>
194→
195→      {error && !isWaiting && <div style={s.error}>{error}</div>}
196→
197→      {isWaiting ? (
198→        <div style={s.empty}>
199→          Waiting for story to send SDUI JSON…
200→          <br />
201→          <span style={{ fontSize: 11, opacity: 0.7 }}>
202→            If this persists, the current story may not use useSDUIJsonEditor().
203→          </span>
204→        </div>
205→      ) : (
206→        <div style={s.editorContainer}>
207→          <CodeMirrorEditor
208→            ref={editorRef}
209→            value={text}
210→            onChange={handleChange}
211→            onValidationChange={handleValidationChange}
212→            isDarkMode={isDarkMode}
213→          />
214→        </div>
215→      )}
216→    </div>
217→  );
218→}
