211→export const CodeMirrorEditor = forwardRef<
212→  CodeMirrorEditorHandle,
213→  CodeMirrorEditorProps
214→>(function CodeMirrorEditor({ value, onChange, onValidationChange, isDarkMode = false }, ref) {
215→  const containerRef = useRef<HTMLDivElement>(null);
216→  const viewRef = useRef<EditorView | null>(null);
217→  const onChangeRef = useRef(onChange);
218→  const onValidationChangeRef = useRef(onValidationChange);
219→  const isExternalUpdate = useRef(false);
220→  const isDarkRef = useRef(isDarkMode);
221→  isDarkRef.current = isDarkMode;
222→
223→  onChangeRef.current = onChange;
224→  onValidationChangeRef.current = onValidationChange;
225→
226→  useImperativeHandle(ref, () => ({
227→    getValue: () => viewRef.current?.state.doc.toString() ?? '',
228→    setValue: (val: string) => {
229→      const view = viewRef.current;
230→      if (!view) return;
231→      isExternalUpdate.current = true;
232→      view.dispatch({
233→        changes: { from: 0, to: view.state.doc.length, insert: val },
234→      });
235→      isExternalUpdate.current = false;
236→    },
237→    getView: () => viewRef.current,
238→  }));
239→
240→  useEffect(() => {
241→    if (!containerRef.current) return;
242→
243→    const json5ParseLinter = linter(
244→      (view): Diagnostic[] => {
245→        const doc = view.state.doc.toString();
246→        if (!doc.trim()) return [];
247→        try {
248→          JSON5.parse(doc);
249→          onValidationChangeRef.current?.(false, null);
250→          return [];
251→        } catch (e) {
252→          const msg = (e as SyntaxError).message || 'Invalid JSON';
253→          const lineMatch = msg.match(/at (\d+):(\d+)/);
254→          let from = 0;
255→          let to = Math.min(doc.length, 1);
256→          if (lineMatch) {
257→            const line = parseInt(lineMatch[1], 10);
258→            const col = parseInt(lineMatch[2], 10);
259→            const lineInfo = view.state.doc.line(Math.min(line, view.state.doc.lines));
260→            from = lineInfo.from + Math.min(col - 1, lineInfo.length);
261→            to = Math.min(from + 1, lineInfo.to);
262→          }
263→          onValidationChangeRef.current?.(true, msg);
264→          return [{ from, to, severity: 'error', message: msg, source: 'json5' }];
265→        }
266→      },
267→      { delay: 300 },
268→    );
269→
270→    const schemaLinter = linter(sduiSchemaLinter, { delay: 500 });
271→
272→    const updateListener = EditorView.updateListener.of(update => {
273→      if (update.docChanged && !isExternalUpdate.current) {
274→        const doc = update.state.doc.toString();
275→        onChangeRef.current(doc);
276→      }
277→    });
278→
279→    const dark = isDarkRef.current;
280→    const themeExtension = dark ? darkTheme : lightTheme;
281→    const highlightExt = dark
282→      ? syntaxHighlighting(darkHighlightStyle)
283→      : syntaxHighlighting(defaultHighlightStyle, { fallback: true });
284→
285→    const state = EditorState.create({
286→      doc: value,
287→      extensions: [
288→        lineNumbers(),
289→        highlightActiveLineGutter(),
290→        highlightActiveLine(),
291→        drawSelection(),
292→        rectangularSelection(),
293→        bracketMatching(),
294→        foldGutter(),
295→        highlightSelectionMatches(),
296→        history(),
297→        javascript(),
298→        highlightExt,
299→        lintGutter(),
300→        json5ParseLinter,
301→        schemaLinter,
302→        themeExtension,
303→        updateListener,
304→        keymap.of([
305→          ...defaultKeymap,
306→          ...historyKeymap,
307→          ...foldKeymap,
308→          ...searchKeymap,
309→          indentWithTab,
310→        ]),
311→        EditorView.lineWrapping,
312→        EditorState.tabSize.of(2),
313→      ],
314→    });
315→
316→    const view = new EditorView({
317→      state,
318→      parent: containerRef.current,
319→    });
320→
321→    viewRef.current = view;
322→
323→    return () => {
324→      view.destroy();
325→      viewRef.current = null;
326→    };
327→  }, [isDarkMode]);
328→
329→  useEffect(() => {
330→    const view = viewRef.current;
331→    if (!view) return;
332→    const currentDoc = view.state.doc.toString();
333→    if (currentDoc !== value) {
334→      isExternalUpdate.current = true;
335→      view.dispatch({
336→        changes: { from: 0, to: view.state.doc.length, insert: value },
337→      });
338→      isExternalUpdate.current = false;
339→    }
340→  }, [value]);
341→
342→  return (
343→    <div
344→      ref={containerRef}
345→      style={{ height: '100%', overflow: 'hidden' }}
346→    />
347→  );
348→});
